--==================================================== -- 🔐 ROLE + KEY SYSTEM (MERGED CLEAN) --==================================================== local Players = game:GetService("Players") local LocalPlayer = Players.LocalPlayer -- 🔑 KEYS PER ROLE local Keys = { OWNER = "Spongecop2026", VIP = "ViP_09!", BUYER = "Buyer_7" } local KeyFile = "OwnerPanelKey.txt" local RoleFile = "OwnerPanelRole.txt" local UserRole = "NONE" -- SAVE / LOAD local function SaveData(key, role) pcall(function() if writefile then writefile(KeyFile, key) writefile(RoleFile, role) end end) end local function LoadData() local key, role pcall(function() if readfile and isfile then if isfile(KeyFile) then key = readfile(KeyFile) end if isfile(RoleFile) then role = readfile(RoleFile) end end end) return key, role end -- ACCESS CHECK local function HasAccess() local savedKey, savedRole = LoadData() if savedKey and savedRole and Keys[savedRole] == savedKey then UserRole = savedRole return true end return false end --==================================================== -- 🔐 KEY UI (ROLE + KEY REQUIRED) --==================================================== if not HasAccess() then local gui = Instance.new("ScreenGui") pcall(function() gui.Parent = game.CoreGui end) local frame = Instance.new("Frame", gui) frame.Size = UDim2.new(0,300,0,220) frame.Position = UDim2.new(0.5,-150,0.5,-110) frame.BackgroundColor3 = Color3.fromRGB(25,25,25) local title = Instance.new("TextLabel", frame) title.Size = UDim2.new(1,0,0,30) title.Text = "Select Role + Enter Key" title.BackgroundTransparency = 1 title.TextColor3 = Color3.new(1,1,1) local roleBox = Instance.new("TextBox", frame) roleBox.Size = UDim2.new(1,-20,0,40) roleBox.Position = UDim2.new(0,10,0,40) roleBox.PlaceholderText = "OWNER / VIP / BUYER" local keyBox = Instance.new("TextBox", frame) keyBox.Size = UDim2.new(1,-20,0,40) keyBox.Position = UDim2.new(0,10,0,90) keyBox.PlaceholderText = "Enter Key..." local btn = Instance.new("TextButton", frame) btn.Size = UDim2.new(1,-20,0,40) btn.Position = UDim2.new(0,10,0,150) btn.Text = "Submit" local passed = false btn.MouseButton1Click:Connect(function() local role = string.upper(roleBox.Text) local key = keyBox.Text if Keys[role] and Keys[role] == key then UserRole = role SaveData(key, role) passed = true gui:Destroy() else keyBox.Text = "Invalid Role or Key" end end) repeat task.wait() until passed end --==================================================== -- 📦 LOAD LIBS --==================================================== local Rayfield pcall(function() Rayfield = loadstring(game:HttpGet('https://sirius.menu/rayfield'))() end) if not Rayfield then warn("Rayfield failed to load") return end local ESP pcall(function() ESP = loadstring(game:HttpGet("https://raw.githubusercontent.com/linemaster2/esp-library/main/library.lua"))() end) --==================================================== -- 🎮 SERVICES --==================================================== local Camera = workspace.CurrentCamera local UIS = game:GetService("UserInputService") local RunService = game:GetService("RunService") --==================================================== -- VARIABLES --==================================================== local aimbotEnabled = false local smoothAim = false local aiming = false local smoothness = 0.15 local aimPart = "Head" local teamCheck = false local IJ = false --==================================================== -- 🎯 AIM SYSTEM --==================================================== local function getClosest() local closest, dist = nil, math.huge for _, plr in pairs(Players:GetPlayers()) do if plr ~= LocalPlayer and plr.Character and plr.Character:FindFirstChild(aimPart) then if teamCheck and plr.Team == LocalPlayer.Team then continue end local pos, visible = Camera:WorldToViewportPoint(plr.Character[aimPart].Position) if visible then local diff = (Vector2.new(pos.X, pos.Y) - UIS:GetMouseLocation()).Magnitude if diff < dist then dist = diff closest = plr.Character end end end end return closest end UIS.InputBegan:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseButton2 then aiming = true end end) UIS.InputEnded:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseButton2 then aiming = false end end) RunService.RenderStepped:Connect(function() if not aimbotEnabled then return end local target = getClosest() if not target or not target:FindFirstChild(aimPart) then return end local targetCF = CFrame.new(Camera.CFrame.Position, target[aimPart].Position) if smoothAim then Camera.CFrame = Camera.CFrame:Lerp(targetCF, smoothness) else if aiming then Camera.CFrame = targetCF end end end) --==================================================== -- 🦘 INFINITE JUMP --==================================================== UIS.JumpRequest:Connect(function() if IJ and LocalPlayer.Character then LocalPlayer.Character:FindFirstChildOfClass("Humanoid"):ChangeState("Jumping") end end) --==================================================== -- 🧠 UI --==================================================== local Window = Rayfield:CreateWindow({ Name = "OWNER PANEL", LoadingTitle = "Loading...", LoadingSubtitle = "Stable Build", Theme = "Ocean", ConfigurationSaving = {Enabled = true, FileName = "OwnerPanel"} }) -- ROLE TAB local RoleTab = Window:CreateTab("Role", 4483362458) RoleTab:CreateLabel("Your Role: " .. UserRole) -- AIMBOT TAB local AimbotTab = Window:CreateTab("Aimbot", 4483362458) AimbotTab:CreateToggle({ Name = "Enable Aimbot", CurrentValue = false, Callback = function(v) aimbotEnabled = v end }) AimbotTab:CreateToggle({ Name = "Smooth Aim (VIP+)", CurrentValue = false, Callback = function(v) if UserRole == "OWNER" or UserRole == "VIP" then smoothAim = v else Rayfield:Notify({ Title = "Locked", Content = "VIP or OWNER only", Duration = 3 }) end end }) AimbotTab:CreateSlider({ Name = "Smoothness", Range = {1,100}, Increment = 1, CurrentValue = 15, Callback = function(v) smoothness = v/100 end }) -- ESP TAB local ESPTab = Window:CreateTab("ESP", 4483362458) if ESP then ESPTab:CreateToggle({ Name = "Enable ESP", CurrentValue = false, Callback = function(v) ESP.Enabled = v end }) end -- PLAYER TAB local PlayerTab = Window:CreateTab("Player", 4483362458) PlayerTab:CreateToggle({ Name = "Infinite Jump", CurrentValue = false, Callback = function(v) IJ = v end }) PlayerTab:CreateSlider({ Name = "WalkSpeed", Range = {16,100}, Increment = 1, CurrentValue = 16, Callback = function(v) if LocalPlayer.Character then LocalPlayer.Character.Humanoid.WalkSpeed = v end end }) -- INFO TAB local InfoTab = Window:CreateTab("Info", 4483362458) InfoTab:CreateLabel("Owner Panel Loaded") InfoTab:CreateLabel("Role System Enabled")
